// ─── Fallback ──────────────────────────────────────────────────────────────
// Spa-Francorchamps is the fallback for any unknown circuit_key.
// It is a proper real circuit, NOT a made-up placeholder.
export const FALLBACK_CIRCUIT_KEY = 7
export const FALLBACK_CIRCUIT: CircuitData = circuitMap[7]

/**
 * Look up circuit data by OpenF1 circuit_key.
 * Falls back to Spa-Francorchamps for any circuit not in our database.
 */
export function getCircuitData(circuitKey: number | null | undefined): CircuitData {
  if (circuitKey != null && circuitMap[circuitKey]) {
    return circuitMap[circuitKey]
  }
  return FALLBACK_CIRCUIT  // Spa — real circuit, safe fallback
}

export default circuitMap
